"""Minimal test script to verify the fix for nullable pandas dtypes."""
import sys
import pandas as pd
import numpy as np
from scipy.sparse import issparse
from collections.abc import Sequence
import warnings

# Copy the relevant functions here for testing
def _unique_multiclass(y):
    if hasattr(y, "__array__"):
        return np.unique(np.asarray(y))
    else:
        return set(y)

def _unique_indicator(y):
    # Simplified version
    return np.arange(y.shape[1])

_FN_UNIQUE_LABELS = {
    "binary": _unique_multiclass,
    "multiclass": _unique_multiclass,
    "multilabel-indicator": _unique_indicator,
}

def is_multilabel(y):
    """Simplified version of is_multilabel."""
    if hasattr(y, "__array__") or isinstance(y, Sequence):
        with warnings.catch_warnings():
            warnings.simplefilter("error", np.VisibleDeprecationWarning)
            try:
                y = np.asarray(y)
            except (np.VisibleDeprecationWarning, ValueError):
                y = np.asarray(y, dtype=object)

    if not (hasattr(y, "shape") and y.ndim == 2 and y.shape[1] > 1):
        return False

    return False  # Simplified

def type_of_target(y, input_name=""):
    """Modified version with nullable pandas dtype support."""
    valid = (
        (isinstance(y, Sequence) or issparse(y) or hasattr(y, "__array__"))
        and not isinstance(y, str)
    )

    if not valid:
        raise ValueError(
            "Expected array-like (array or non-string sequence), got %r" % y
        )

    sparse_pandas = y.__class__.__name__ in ["SparseSeries", "SparseArray"]
    if sparse_pandas:
        raise ValueError("y cannot be class 'SparseSeries' or 'SparseArray'")

    # Handle pandas nullable dtypes by converting to appropriate numpy dtype
    # before further processing. Pandas nullable dtypes (Int64, Float64, boolean)
    # become object dtype when converted with np.asarray(), which causes issues.
    if hasattr(y, "dtype") and hasattr(y.dtype, "name"):
        dtype_name = y.dtype.name
        # Check if this is a pandas nullable dtype
        if dtype_name in ("Int8", "Int16", "Int32", "Int64",
                          "UInt8", "UInt16", "UInt32", "UInt64",
                          "Float32", "Float64", "boolean"):
            # Convert to numpy array with appropriate dtype
            # Use to_numpy() to handle the conversion properly
            if hasattr(y, "to_numpy"):
                # Map nullable dtypes to numpy dtypes
                dtype_mapping = {
                    "Int8": np.int8, "Int16": np.int16, "Int32": np.int32, "Int64": np.int64,
                    "UInt8": np.uint8, "UInt16": np.uint16, "UInt32": np.uint32, "UInt64": np.uint64,
                    "Float32": np.float32, "Float64": np.float64,
                    "boolean": bool,
                }
                numpy_dtype = dtype_mapping.get(dtype_name)
                if numpy_dtype is not None:
                    # Convert NA values to NaN for float types or handle them appropriately
                    if dtype_name.startswith("Float"):
                        y = y.to_numpy(dtype=numpy_dtype, na_value=np.nan)
                    elif dtype_name == "boolean":
                        # For boolean, we need to handle NA values
                        # Convert to float first if there are NAs, otherwise to bool
                        if y.isna().any():
                            # If there are NA values, convert to float
                            y = y.to_numpy(dtype=np.float64, na_value=np.nan)
                        else:
                            y = y.to_numpy(dtype=numpy_dtype)
                    else:
                        # For integer types with NA, convert to float
                        if y.isna().any():
                            y = y.to_numpy(dtype=np.float64, na_value=np.nan)
                        else:
                            y = y.to_numpy(dtype=numpy_dtype)

    if is_multilabel(y):
        return "multilabel-indicator"

    with warnings.catch_warnings():
        warnings.simplefilter("error", np.VisibleDeprecationWarning)
        if not issparse(y):
            try:
                y = np.asarray(y)
            except (np.VisibleDeprecationWarning, ValueError):
                y = np.asarray(y, dtype=object)

    # The old sequence of sequences format
    try:
        if (
            not hasattr(y[0], "__array__")
            and isinstance(y[0], Sequence)
            and not isinstance(y[0], str)
        ):
            raise ValueError(
                "You appear to be using a legacy multi-label data"
                " representation."
            )
    except IndexError:
        pass

    # Invalid inputs
    if y.ndim not in (1, 2):
        return "unknown"
    if not min(y.shape):
        if y.ndim == 1:
            return "binary"
        return "unknown"
    if not issparse(y) and y.dtype == object and not isinstance(y.flat[0], str):
        return "unknown"

    # Check if multioutput
    if y.ndim == 2 and y.shape[1] > 1:
        suffix = "-multioutput"
    else:
        suffix = ""

    # Check float and contains non-integer float values
    if y.dtype.kind == "f":
        data = y.data if issparse(y) else y
        if np.any(data != data.astype(int)):
            return "continuous" + suffix

    # Check multiclass
    first_row = y[0] if not issparse(y) else y.getrow(0).data
    if np.unique(y).shape[0] > 2 or (y.ndim == 2 and len(first_row) > 1):
        return "multiclass" + suffix
    else:
        return "binary"


def unique_labels(*ys):
    """Extract an ordered array of unique labels."""
    if not ys:
        raise ValueError("No argument has been passed.")

    ys_types = set(type_of_target(x) for x in ys)
    if ys_types == {"binary", "multiclass"}:
        ys_types = {"multiclass"}

    if len(ys_types) > 1:
        raise ValueError("Mix type of y not allowed, got types %s" % ys_types)

    label_type = ys_types.pop()

    _unique_labels = _FN_UNIQUE_LABELS.get(label_type, None)
    if not _unique_labels:
        raise ValueError("Unknown label type: %s" % repr(ys))

    ys_labels = set()
    for y in ys:
        for label in _unique_labels(y):
            ys_labels.add(label)

    # Check that we don't mix string type with number type
    if len(set(isinstance(label, str) for label in ys_labels)) > 1:
        raise ValueError("Mix of label input types (string and number)")

    return np.asarray(sorted(ys_labels))


# Run tests
print("Testing nullable pandas dtypes...")
print("=" * 60)
print()

# Test type_of_target with nullable dtypes
print("Test 1: type_of_target with nullable pandas dtypes")
print("-" * 60)
for dtype in ["Int64", "Float64", "boolean"]:
    y = pd.Series([1, 0, 0, 1, 0, 1, 1, 0, 1], dtype=dtype)
    print(f"  dtype={dtype:8s}, numpy_dtype={np.asarray(y).dtype}")
    try:
        result = type_of_target(y)
        print(f"  ✓ type_of_target={result}")
    except Exception as e:
        print(f"  ✗ ERROR: {e}")
    print()

# Test unique_labels with nullable dtypes
print("Test 2: unique_labels with nullable pandas dtypes")
print("-" * 60)
for dtype in ["Int64", "Float64", "boolean"]:
    y_true = pd.Series([1, 0, 0, 1, 0, 1, 1, 0, 1], dtype=dtype)
    y_predicted = pd.Series([0, 0, 1, 1, 0, 1, 1, 1, 1], dtype="int64")

    print(f"  y_true dtype={dtype}, y_predicted dtype=int64")
    try:
        result = unique_labels(y_true, y_predicted)
        print(f"  ✓ unique_labels={result}")
    except Exception as e:
        print(f"  ✗ ERROR: {e}")
    print()

# Test that regular dtypes still work
print("Test 3: unique_labels with regular pandas dtypes (regression test)")
print("-" * 60)
for dtype in ["int64", "float64", "bool"]:
    y_true = pd.Series([1, 0, 0, 1, 0, 1, 1, 0, 1], dtype=dtype)
    y_predicted = pd.Series([0, 0, 1, 1, 0, 1, 1, 1, 1], dtype="int64")

    try:
        result = unique_labels(y_true, y_predicted)
        print(f"  ✓ dtype={dtype:8s} -> unique_labels={result}")
    except Exception as e:
        print(f"  ✗ dtype={dtype:8s} -> ERROR: {e}")

print()
print("=" * 60)
print("Testing complete!")

